-- Sheets 01–04: feature catalogue, module summary, roles, workflows

CREATE TABLE IF NOT EXISTS "engage360"."feature_catalogue" (
    "id" TEXT NOT NULL, "domain" TEXT NOT NULL, "module" TEXT NOT NULL,
    "capability" TEXT NOT NULL, "featureName" TEXT NOT NULL,
    "status" TEXT NOT NULL DEFAULT 'Not Started', "phase" TEXT, "priority" TEXT,
    "cursorDone" BOOLEAN NOT NULL DEFAULT false,
    CONSTRAINT "feature_catalogue_pkey" PRIMARY KEY ("id")
);
CREATE INDEX IF NOT EXISTS "feature_catalogue_domain_module_idx" ON "engage360"."feature_catalogue"("domain", "module");
CREATE INDEX IF NOT EXISTS "feature_catalogue_status_idx" ON "engage360"."feature_catalogue"("status");

CREATE TABLE IF NOT EXISTS "engage360"."module_summary" (
    "id" TEXT NOT NULL, "domain" TEXT NOT NULL, "submodules" INTEGER NOT NULL,
    "featureRows" INTEGER NOT NULL, "mustCount" INTEGER NOT NULL, "shouldCount" INTEGER NOT NULL,
    "storyPoints" INTEGER NOT NULL, "phase" TEXT NOT NULL,
    CONSTRAINT "module_summary_pkey" PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "engage360"."role_definitions" (
    "id" TEXT NOT NULL, "role" TEXT NOT NULL, "persona" TEXT NOT NULL, "scope" TEXT NOT NULL,
    "capabilities" TEXT NOT NULL, "sensitiveAccess" TEXT NOT NULL, "approvalRights" TEXT NOT NULL,
    "boundary" TEXT NOT NULL, "sodNotes" TEXT NOT NULL, "systemRole" TEXT,
    CONSTRAINT "role_definitions_pkey" PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "engage360"."workflow_definitions" (
    "id" TEXT NOT NULL, "name" TEXT NOT NULL, "trigger" TEXT NOT NULL, "stages" TEXT NOT NULL,
    "actors" TEXT NOT NULL, "outcome" TEXT NOT NULL, "exceptions" TEXT,
    "implemented" BOOLEAN NOT NULL DEFAULT false, "systemFlow" TEXT,
    CONSTRAINT "workflow_definitions_pkey" PRIMARY KEY ("id")
);

-- Sheet 02 module summary
ON CONFLICT (id) DO NOTHING;

-- Sheet 03 roles
ON CONFLICT (id) DO NOTHING;

-- Sheet 04 workflows (core hire-to-exit flows — implemented in codebase)
ON CONFLICT (id) DO NOTHING;

